1307	// ── Tabtarget-refusal cases ─────────────────────────────────
1308	
1309	/// rbw-dU empty-arg refusal — BBAA9 contract. Invoking rbw-dU with no
1310	/// argument must die non-zero and emit the rbw-dl pointer (operator
1311	/// discovery for candidate depot project IDs). BUW dispatch merges
1312	/// stderr→stdout via `2>&1` (bud_dispatch.sh:372), so the captured
1313	/// stdout carries the buc_warn/buc_info/buc_tabtarget/buc_die output
1314	/// from rbgp_depot_unmake's no-arg branch (rbgp_Payor.sh:937-942).
1315	///
1316	/// Pure shell, no GCP traffic — refusal lands before authenticate.
1317	fn rbtdrf_rs_unmake_empty_arg_refusal(dir: &Path) -> rbtdre_Verdict {
1318	    let root = match std::env::current_dir() {
1319	        Ok(r) => r,
1320	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1321	    };
1322	
1323	    let tt = match rbtdri_find_tabtarget_global(&root, "rbw-dU") {
1324	        Ok(p) => p,
1325	        Err(e) => return rbtdre_Verdict::Fail(e),
1326	    };
1327	
1328	    let output = match Command::new(&tt).current_dir(&root).output() {
1329	        Ok(o) => o,
1330	        Err(e) => {
1331	            return rbtdre_Verdict::Fail(format!(
1332	                "failed to run {}: {}",
1333	                tt.display(),
1334	                e
1335	            ));
1336	        }
1337	    };
1338	
1339	    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
1340	    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
1341	    let code = output.status.code().unwrap_or(-1);
1342	    let _ = std::fs::write(dir.join("empty-arg-stdout.txt"), &stdout);
1343	    let _ = std::fs::write(dir.join("empty-arg-stderr.txt"), &stderr);
1344	
1345	    if code == 0 {
1346	        return rbtdre_Verdict::Fail(
1347	            "rbw-dU exited 0 with no argument — BBAA9 empty-arg refusal contract violated"
1348	                .to_string(),
1349	        );
1350	    }
1351	
1352	    let combined = format!("{}{}", stdout, stderr);
1353	    if !combined.contains("rbw-dl") {
1354	        return rbtdre_Verdict::Fail(format!(
1355	            "rbw-dU empty-arg refusal did not point at rbw-dl for operator discovery\n\
1356	             stdout:\n{}\n\nstderr:\n{}",
1357	            stdout, stderr
1358	        ));
1359	    }
1360	
1361	    rbtdre_Verdict::Pass
1362	}
