1364	// ── Dockerfile-hygiene cases ────────────────────────────────
1365	//
1366	// Drives the Dockerfile FROM-line hygiene contract through the rbw-fhc and
1367	// rbw-fhv tabtargets — exercising the contract surface, not module internals.
1368	// Eight synthetic cases (5 positive, 3 negative) feed inline Dockerfile bodies
1369	// to rbw-fhc; one all-vessels case iterates real conjure vessels through
1370	// rbw-fhv with a Rust-side counter that fails verdict on zero iterations.
1371	
1372	const RBTDRF_DH_BODY_PARAMETERIZED: &str = "FROM ${RBF_IMAGE_1}\n";
1373	const RBTDRF_DH_BODY_SCRATCH: &str = "FROM scratch\n";
1374	const RBTDRF_DH_BODY_MULTISTAGE_AS: &str = "FROM ${RBF_IMAGE_1} AS builder\n";
1375	const RBTDRF_DH_BODY_EMPTY: &str = "";
1376	const RBTDRF_DH_BODY_COMMENTS_ONLY: &str = "# top-level comment\n# another comment\n";
1377	const RBTDRF_DH_BODY_HARDCODED_LITERAL: &str = "FROM python:3.12-slim\n";
1378	const RBTDRF_DH_BODY_TAB_IN_FROM: &str = "FROM\t${RBF_IMAGE_1}\n";
