1388	        Ok(r) => r,
1389	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1390	    };
1391	    let dockerfile = dir.join(format!("{}-Dockerfile", label));
1392	    if let Err(e) = std::fs::write(&dockerfile, body) {
1393	        return rbtdre_Verdict::Fail(format!("{}: write Dockerfile failed: {}", label, e));
1394	    }
1395	    let path_str = dockerfile.to_string_lossy().into_owned();
