1397	        rbtdrf_run_tt(&root, RBTDRM_COLOPHON_HYGIENE_CHECK, &[&path_str], dir, label)
1398	    } else {
1399	        rbtdrf_run_tt_neg(&root, RBTDRM_COLOPHON_HYGIENE_CHECK, &[&path_str], dir, label)
1400	    };
1401	    match result {
