1439	fn rbtdrf_dh_all_vessels_pass(dir: &Path) -> rbtdre_Verdict {
1440	    let root = match std::env::current_dir() {
1441	        Ok(r) => r,
1442	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1443	    };
1444	
1445	    // Resolve RBRR_VESSEL_DIR via one-shot bash (kindle ceremony unavoidable
1446	    // for derived-path resolution).
1447	    let buv = root.join("Tools/buk/buv_validation.sh");
1448	    let rbk = root.join("Tools/rbk");
1449	    let buv_p = rbtdrx_native_to_posix(&buv);
1450	    let rbk_p = rbtdrx_native_to_posix(&rbk);
1451	    let resolve_script = format!(
1452	        "set -euo pipefail\n\
1453	         source '{}'\n\
1454	         source '{}/rbcc_Constants.sh'\n\
1455	         source '{}/rbgc_Constants.sh'\n\
1456	         source '{}/rbrr_regime.sh'\n\
1457	         source '{}/rbrd_regime.sh'\n\
1458	         source '{}/rbdc_DerivedConstants.sh'\n\
1459	         zbuv_kindle\nzrbcc_kindle\n\
1460	         source \"${{PWD}}/.rbk/rbrr.env\"\n\
1461	         source \"${{PWD}}/.rbk/rbrd.env\"\n\
1462	         zrbrr_kindle\nzrbrd_kindle\nzrbrr_enforce\nzrbrd_enforce\nzrbdc_kindle\n\
1463	         printf '%s' \"${{RBRR_VESSEL_DIR}}\"",
1464	        buv_p,
1465	        rbk_p, rbk_p, rbk_p, rbk_p, rbk_p,
1466	    );
1467	    let vessel_dir = match rbtdrf_run_bash(&root, &resolve_script, dir, "resolve-vessel-dir") {
1468	        Ok((0, stdout, _)) => stdout,
1469	        Ok((code, _, stderr)) => {
1470	            return rbtdre_Verdict::Fail(format!(
1471	                "resolve RBRR_VESSEL_DIR failed (exit {}): {}",
1472	                code, stderr
1473	            ));
1474	        }
1475	        Err(e) => return rbtdre_Verdict::Fail(e),
1476	    };
1477	    let vessel_dir = vessel_dir.trim();
1478	    if vessel_dir.is_empty() {
1479	        return rbtdre_Verdict::Fail("RBRR_VESSEL_DIR resolved to empty string".to_string());
1480	    }
1481	
1482	    let entries = match std::fs::read_dir(vessel_dir) {
1483	        Ok(e) => e,
1484	        Err(e) => {
1485	            return rbtdre_Verdict::Fail(format!(
1486	                "read_dir({}) failed: {}",
1487	                vessel_dir, e
1488	            ));
1489	        }
1490	    };
1491	
1492	    // rbw-fhv silently succeeds on non-conjure vessels (hygiene contract is
1493	    // vacuously satisfied where there's no local Dockerfile), so theurge
1494	    // iterates without pre-filtering — surface integrity stays intact and
1495	    // no rbrv.env internals are touched here.
1496	    let mut count: usize = 0;
1497	    for entry in entries {
1498	        let entry = match entry {
1499	            Ok(e) => e,
1500	            Err(e) => return rbtdre_Verdict::Fail(format!("dir entry error: {}", e)),
1501	        };
1502	        let path = entry.path();
1503	        if !path.is_dir() {
1504	            continue;
1505	        }
1506	        if !path.join("rbrv.env").is_file() {
1507	            continue;
1508	        }
1509	        let sigil = match path.file_name().and_then(|s| s.to_str()) {
1510	            Some(s) => s.to_string(),
